<?php ao_schema_ensure_v1200(); $rows=[]; try{$rows=db()->query('SELECT h.*, s.name server_name FROM hosting_health_checks h LEFT JOIN server_nodes s ON s.id=h.server_id ORDER BY h.checked_at DESC LIMIT 200')->fetchAll();}catch(Throwable $e){} ?>
<div class="ao-page-head"><div><h2>Hosting Sağlık Kontrolü</h2><p>Sunucu ve hosting hizmetleri için disk, RAM, load ve operasyon sağlık kayıtları.</p></div><a class="ao-btn soft" href="<?= url('admin/hosting-server/accounts') ?>">Hosting Hesapları</a></div>
